<div class="grid grid-2"><div class="card"><h3>Accurate Connection</h3><p>Status: <span class="badge badge-info"><?=e($conn['status'] ?? 'not configured')?></span></p><p class="muted">Accurate user: <?=e($conn['accurate_user_email'] ?? '-')?></p><form method="post" action="<?=url('/accurate/config')?>"><?=csrf_field()?><label>Client ID</label><input name="client_id" value="<?=e($conn['client_id'] ?? '')?>" required><label>Client Secret</label><input name="client_secret" type="password" placeholder="re-enter to save" required><label>Redirect URI</label><input name="redirect_uri" value="<?=e($conn['redirect_uri'] ?? url('/accurate/callback'))?>" required><label>Scope</label><textarea name="scope"><?=e($conn['scope'] ?? config('accurate.default_scope'))?></textarea><button class="btn btn-primary">Save Config</button> <?php if($conn):?><a class="btn btn-light" href="<?=url('/accurate/connect')?>">Connect Accurate</a><?php endif;?></form></div><div class="card"><h3>Account Mapping</h3><form method="post" action="<?=url('/accurate/mapping')?>"><?=csrf_field()?><label>Mapping Key</label><select name="mapping_key"><option>salary_expense</option><option>allowance_expense</option><option>overtime_expense</option><option>bpjs_company_expense</option><option>salary_payable</option><option>pph21_payable</option><option>bpjs_payable</option><option>employee_loan</option><option>reimbursement_payable</option><option>cash_bank</option></select><label>Local Name</label><input name="local_name" required><label>Accurate Account ID</label><input name="accurate_account_id" required><label>Accurate Account No</label><input name="accurate_account_no" required><label>Accurate Account Name</label><input name="accurate_account_name" required><button class="btn btn-primary">Save Mapping</button></form></div></div><br><div class="grid grid-2"><div class="card"><h3>Current Mappings</h3><table class="table"><tr><th>Key</th><th>Account</th></tr><?php foreach($maps as $m):?><tr><td><?=e($m['mapping_key'])?></td><td><?=e($m['accurate_account_no'].' - '.$m['accurate_account_name'])?></td></tr><?php endforeach;?></table></div><div class="card"><h3>Post Payroll Journal</h3><p class="muted">Input payroll_journals.id yang sudah tervalidasi. Endpoint final harus diverifikasi di API Docs Accurate Developer.</p><form method="post" action="<?=url('/accurate/post-payroll-journal')?>"><?=csrf_field()?><label>Payroll Journal ID</label><input name="journal_id" type="number" required><button class="btn btn-primary">Post to Accurate</button></form></div></div><br><div class="card"><h3>Sync Logs</h3><table class="table"><tr><th>Date</th><th>Entity</th><th>Action</th><th>Status</th><th>Error</th></tr><?php foreach($logs as $l):?><tr><td><?=e($l['created_at'])?></td><td><?=e($l['entity_type'].' #'.$l['entity_id'])?></td><td><?=e($l['action'])?></td><td><span class="badge badge-info"><?=e($l['status'])?></span></td><td><?=e($l['error_message'])?></td></tr><?php endforeach;?></table></div>
